import { test, expect } from '@playwright/test';

test.describe('TRS Homepage Cross-Browser Tests', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
  });

  test('should load homepage in all browsers', async ({ page }) => {
    await expect(page).toHaveTitle(/TRS Web/);
    await expect(page.locator('h1')).toContainText('Welcome to TRS Web');
    await expect(page.locator('[data-testid="tourvest-heading"]')).toContainText('Tourvest Retail Services');
  });

  test('should have working navigation elements', async ({ page }) => {
    await expect(page.locator('[data-testid="home-link"]')).toBeVisible();
    await expect(page.locator('[data-testid="theme-toggle"]')).toBeVisible();
    await expect(page.locator('[data-testid="sign-in-button"]')).toBeVisible();
  });

  test('should handle theme toggle across browsers', async ({ page }) => {
    const themeToggle = page.locator('[data-testid="theme-toggle"]');
    await themeToggle.click();
    
    // Check if theme changed (implementation depends on how theme is applied)
    await expect(page.locator('body')).toHaveAttribute('data-theme', 'dark');
  });

  test('should be responsive on mobile devices', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 667 });
    await expect(page.locator('[data-testid="mobile-menu-toggle"]')).toBeVisible();
    
    await page.locator('[data-testid="mobile-menu-toggle"]').click();
    await expect(page.locator('[data-testid="mobile-menu"]')).toBeVisible();
  });
});